int binary_search(int n, int *a, int target)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      (forall (i: Z), (0 <= i && i + 1 < n) => l[i] <= l[i + 1]) &&
      IntArray::full(a, n, l)
    Ensure
      (((__return == -1) &&
        (forall (i: Z), (0 <= i && i < n) => l[i] != target)) ||
       ((__return != -1) &&
        0 <= __return && __return < n &&
        l[__return] == target)) &&
      IntArray::full(a, n, l)
*/
{
    int left = 0;
    int right = n - 1;
    int mid;

    while (left <= right) {
        mid = left + (right - left) / 2;
        if (a[mid] == target) {
            return mid;
        }
        if (a[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return -1;
}

